#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long best = 0, cur = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(x>=0){
                cur += x;
                if(cur>best) best = cur;
            }else{
                cur = 0;
            }
        }
        printf("%lld\n", best);
    }
    return 0;
}

