import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        best = cur = 0
        for _ in range(N):
            x = int(next(it))
            if x >= 0:
                cur += x
                if cur > best:
                    best = cur
            else:
                cur = 0
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

